{"file_path":"/Users/bill/Documents/solo/workspaces/yzz00155/src/types/index.ts","content":"export type MaterialStatus = '可办理' | '需补充' | '已锁定' | '失败';

export interface SortingRequest {
  businessNo: string;
  objectStatus: string;
  timeWindow: {
    start: string;
    end: string;
  };
  ruleVersion: string;
  operator: string;
}

export interface SortingResponse {
  businessNo: string;
  status: MaterialStatus;
  failedReason?: string;
  supplementItems?: string[];
  lockReason?: string;
  ruleVersion: string;
  operator: string;
  auditRecord: AuditRecord;
}

export interface AuditRecord {
  id: string;
  businessNo: string;
  operator: string;
  operationTime: string;
  requestDetails: SortingRequest;
  resultDetails: {
    status: MaterialStatus;
    reason?: string;
  };
  ruleVersion: string;
  isRechecked: boolean;
  recheckedBy?: string;
  recheckedTime?: string;
}

export interface RuleConfig {
  version: string;
  effectiveTime: {
    start: string;
    end: string;
  };
  businessRules: BusinessRule[];
  supplementRules: SupplementRule[];
  lockRules: LockRule[];
}

export interface BusinessRule {
  id: string;
  name: string;
  condition: (request: SortingRequest) => boolean;
  description: string;
}

export interface SupplementRule {
  id: string;
  name: string;
  condition: (request: SortingRequest) => boolean;
  supplementItem: string;
}

export interface LockRule {
  id: string;
  name: string;
  condition: (request: SortingRequest) => boolean;
  lockReason: string;
}

export interface ProcessedResult {
  success: boolean;
  request: SortingRequest;
  response?: SortingResponse;
  error?: string;
  processedAt: string;
}

export interface BadRecord {
  rowIndex: number;
  request: SortingRequest;
  errorType: string;
  errorMessage: string;
  timestamp: string;
}

export interface ResultFile {
  totalCount: number;
  successCount: number;
  failedCount: number;
  badRecordCount: number;
  processedAt: string;
  results: ProcessedResult[];
  badRecords: BadRecord[];
}
"}

