export const VALID_BUSINESS_PREFIXES = ['CL', 'BX', 'ZF'];
export const RULE_CONFIGS: Map<string, RuleConfig> = new Map();

const ruleV1: RuleConfig = {
  version: 'v1.0',
  effectiveTime: {
    start: '2024-01-01T00:00:00',
    end: '2024-12-31T23:59:59'
  },
  businessRules: [
    {
      id: 'BR001',
