    },
    {
      id: 'SR003',
      name: '缺少费用凭证',
      condition: (req: SortingRequest) => req.objectStatus === 'MISSING_INVOICE',
      supplementItem: '费用原始凭证'
    }
  ],
  lockRules: [
    {
      id: 'LR001',
      name: '涉及司法纠纷',
      condition: (req: SortingRequest) => req.objectStatus === 'JUDICIAL_DISPUTE',
      lockReason: '该理赔案件涉及司法纠纷，已锁定待处理'
    },
    {
      id: 'LR002',
      name: '涉嫌欺诈风险',
      condition: (req: SortingRequest) => req.objectStatus === 'FRAUD_SUSPECTED',
      lockReason: '该理赔案件涉嫌欺诈，已锁定待核查'
    }
  ]
};

const ruleV2: RuleConfig = {
  version: 'v2.0',
  effectiveTime: {
    start: '2025-01-01T00:00:00',
    end: '2099-12-31T23:59:59'
  },
  businessRules: [
    {
      id: 'BR001',
      name: '正常理赔状态',
      condition: (req: SortingRequest) => req.objectStatus === 'NORMAL',
      description: '理赔对象状态正常'
    },
    {
      id: 'BR002',
      name: '快速理赔通道',
      condition: (req: SortingRequest) => req.objectStatus === 'FAST_TRACK',
      description: '符合快速理赔通道条件'
    }
  ],
  supplementRules: [
    {
      id: 'SR001',
      name: '缺少身份证明',
      condition: (req: SortingRequest) => req.objectStatus === 'MISSING_ID',
      supplementItem: '身份证明材料'
    },
    {
      id: 'SR002',
      name: '缺少医疗证明',
      condition: (req: SortingRequest) => req.objectStatus === 'MISSING_MEDICAL',
      supplementItem: '医疗诊断证明'
    },
    {
      id: 'SR003',
      name: '缺少费用凭证',
      condition: (req: SortingRequest) => req.objectStatus === 'MISSING_INVOICE',
      supplementItem: '费用原始凭证'
    },
    {
      id: 'SR004',
      name: '缺少受益人证明',
      condition: (req: SortingRequest) => req.objectStatus === 'MISSING_BENEFICIARY',
      supplementItem: '受益人资格证明'
    }
  ],
  lockRules: [
    {
      id: 'LR001',
      name: '涉及司法纠纷',
      condition: (req: SortingRequest) => req.objectStatus === 'JUDICIAL_DISPUTE',
      lockReason: '该理赔案件涉及司法纠纷，已锁定待处理'
    },
    {
      id: 'LR002',
      name: '涉嫌欺诈风险',
      condition: (req: SortingRequest) => req.objectStatus === 'FRAUD_SUSPECTED',
      lockReason: '该理赔案件涉嫌欺诈，已锁定待核查'
    },
    {
      id: 'LR003',
      name: '超额理赔预警',
      condition: (req: SortingRequest) => req.objectStatus === 'OVER_LIMIT',
      lockReason: '该理赔金额超出限额，已锁定待审核'
    }
  ]
};

RULE_CONFIGS.set('v1.0', ruleV1);
RULE_CONFIGS.set('v2.0', ruleV2);

export const DEFAULT_RULE_VERSION = 'v2.0';

export function isValidBusinessNo(businessNo: string): boolean {
  if (!businessNo || typeof businessNo !== 'string') return false;
  if (businessNo.length !== 12) return false;
  const prefix = businessNo.substring(0, 2);
  if (!VALID_BUSINESS_PREFIXES.includes(prefix)) return false;
  const numericPart = businessNo.substring(2);
  return /^\d{10}$/.test(numericPart);
}

export function isValidTimeWindow(start: string, end: string): boolean {
  try {
    const startTime = new Date(start).getTime();
    const endTime = new Date(end).getTime();
    if (isNaN(startTime) || isNaN(endTime)) return false;
    return startTime <= endTime;
  } catch {
    return false;
  }
}

export function isTimeInRange(time: string, start: string, end: string): boolean {
  try {
    const checkTime = new Date(time).getTime();
    const startTime = new Date(start).getTime();
    const endTime = new Date(end).getTime();
    return checkTime >= startTime && checkTime <= endTime;
  } catch {
    return false;
  }
}
"}

