{"file_path":"/Users/bill/Documents/solo/workspaces/yzz00155/src/engine/ruleEngine.ts","content":"import { v4 as uuidv4 } from 'uuid';
import {
  SortingRequest,
  SortingResponse,
  MaterialStatus,
  AuditRecord,
  RuleConfig
} from '../types';
import {
  RULE_CONFIGS,
  DEFAULT_RULE_VERSION,
  isValidBusinessNo,
  isValidTimeWindow,
  isTimeInRange
} from '../config/rules';

export class RuleEngine {
  private ruleConfigs: Map<string, RuleConfig>;
  private resultCache: Map<string, SortingResponse>;
  private auditLogs: AuditRecord[];

  constructor() {
    this.ruleConfigs = RULE_CONFIGS;
    this.resultCache = new Map();
    this.auditLogs = [];
  }

  private generateCacheKey(request: SortingRequest): string {
    return `${request.businessNo}-${request.objectStatus}-${request.timeWindow.start}-${request.timeWindow.end}-${request.ruleVersion}`;
  }

  private createAuditRecord(
    request: SortingRequest,
    status: MaterialStatus,
    reason?: string
  ): AuditRecord {
    return {
      id: uuidv4(),
      businessNo: request.businessNo,
      operator: request.operator,
      operationTime: new Date().toISOString(),
      requestDetails: JSON.parse(JSON.stringify(request)),
      resultDetails: {
        status,
        reason
      },
      ruleVersion: request.ruleVersion,
      isRechecked: false
    };
  }

  public validateRequest(request: SortingRequest): { valid: boolean; error?: string } {
    if (!request.businessNo) {
      return { valid: false, error: '业务编号不能为空' };
    }
    if (!isValidBusinessNo(request.businessNo)) {
      return { valid: false, error: '业务编号格式错误，应为2位前缀+10位数字' };
    }
    if (!request.objectStatus) {
      return { valid: false, error: '对象状态不能为空' };
    }
    if (!request.timeWindow || !request.timeWindow.start || !request.timeWindow.end) {
      return { valid: false, error: '时间窗口参数不完整' };
    }
    if (!isValidTimeWindow(request.timeWindow.start, request.timeWindow.end)) {
      return { valid: false, error: '时间窗口格式无效或开始时间晚于结束时间' };
    }
    if (!request.ruleVersion) {
      return { valid: false, error: '规则版本不能为空' };
    }
    if (!this.ruleConfigs.has(request.ruleVersion)) {
      return { valid: false, error: `规则版本 ${request.ruleVersion} 不存在` };
    }
    if (!request.operator) {
      return { valid: false, error: '操作人不能为空' };
    }
    return { valid: true };
  }

  public checkTimeBoundary(request: SortingRequest): { inRange: boolean; error?: string } {
    const ruleConfig = this.ruleConfigs.get(request.ruleVersion);
    if (!ruleConfig) {
      return { inRange: false, error: '规则配置不存在' };
    }
    const midTime = new Date(
      (new Date(request.timeWindow.start).getTime() + new Date(request.timeWindow.end).getTime()) / 2
    ).toISOString();
    if (!isTimeInRange(midTime, ruleConfig.effectiveTime.start, ruleConfig.effectiveTime.end)) {
      return {
        inRange: false,
        error: `请求时间超出规则版本 ${request.ruleVersion} 的有效时间范围 (${ruleConfig.effectiveTime.start} ~ ${ruleConfig.effectiveTime.end})`
      };
    }
    return { inRange: true };
  }

  public process(request: SortingRequest): SortingResponse {
    const cacheKey = this.generateCacheKey(request);
    if (this.resultCache.has(cacheKey)) {
      console.log(`[CACHE_HIT] 业务编号 ${request.businessNo} 使用缓存结果`);
      return this.resultCache.get(cacheKey)!;
    }
    const validation = this.validateRequest(request);
    if (!validation.valid) {
      const auditRecord = this.createAuditRecord(request, '失败', validation.error);
      const response: SortingResponse = {
        businessNo: request.businessNo,
        status: '失败',
        failedReason: validation.error,
        ruleVersion: request.ruleVersion || DEFAULT_RULE_VERSION,
        operator: request.operator,
        auditRecord
      };
      this.resultCache.set(cacheKey, response);
      this.auditLogs.push(auditRecord);
      console.log(`[VALIDATION_FAILED] 业务编号 ${request.businessNo}: ${validation.error}`);
      return response;
    }
    const timeCheck = this.checkTimeBoundary(request);
