      const response: SortingResponse = {
        businessNo: request.businessNo,
        status: '失败',
        failedReason: timeCheck.error,
        ruleVersion: request.ruleVersion,
        operator: request.operator,
        auditRecord
      };
      this.resultCache.set(cacheKey, response);
      this.auditLogs.push(auditRecord);
      console.log(`[TIME_OUT_OF_RANGE] 业务编号 ${request.businessNo}: ${timeCheck.error}`);
      return response;
    }
    const ruleConfig = this.ruleConfigs.get(request.ruleVersion)!;
    for (const lockRule of ruleConfig.lockRules) {
      if (lockRule.condition(request)) {
        const auditRecord = this.createAuditRecord(request, '已锁定', lockRule.lockReason);
        const response: SortingResponse = {
          businessNo: request.businessNo,
          status: '已锁定',
          lockReason: lockRule.lockReason,
          ruleVersion: request.ruleVersion,
          operator: request.operator,
          auditRecord
        };
        this.resultCache.set(cacheKey, response);
        this.auditLogs.push(auditRecord);
        console.log(`[LOCKED] 业务编号 ${request.businessNo}: ${lockRule.lockReason}`);
        return response;
      }
    }
    const supplementItems: string[] = [];
    for (const supplementRule of ruleConfig.supplementRules) {
      if (supplementRule.condition(request)) {
        supplementItems.push(supplementRule.supplementItem);
      }
    }
    if (supplementItems.length > 0) {
      const reason = `需补充材料: ${supplementItems.join('、')}`;
      const auditRecord = this.createAuditRecord(request, '需补充', reason);
      const response: SortingResponse = {
        businessNo: request.businessNo,
        status: '需补充',
        supplementItems,
        ruleVersion: request.ruleVersion,
        operator: request.operator,
        auditRecord
      };
      this.resultCache.set(cacheKey, response);
      this.auditLogs.push(auditRecord);
      console.log(`[SUPPLEMENT_NEEDED] 业务编号 ${request.businessNo}: ${reason}`);
      return response;
    }
    for (const businessRule of ruleConfig.businessRules) {
      if (businessRule.condition(request)) {
        const auditRecord = this.createAuditRecord(request, '可办理', businessRule.description);
        const response: SortingResponse = {
