      status: '失败',
      failedReason: unknownReason,
      ruleVersion: request.ruleVersion,
      operator: request.operator,
      auditRecord
    };
    this.resultCache.set(cacheKey, response);
    this.auditLogs.push(auditRecord);
    console.log(`[NO_RULE_MATCHED] 业务编号 ${request.businessNo}: ${unknownReason}`);
    return response;
  }

