  }

  public getAuditLogById(id: string): AuditRecord | undefined {
    return this.auditLogs.find(log => log.id === id);
  }

  public clearCache(): void {
    this.resultCache.clear();
    console.log('[CACHE_CLEARED] 结果缓存已清空');
  }
}

