{"file_path":"/Users/bill/Documents/solo/workspaces/yzz00155/src/utils/fileManager.ts","content":"import * as fs from 'fs';
import * as path from 'path';
import {
  SortingRequest,
  SortingResponse,
  ProcessedResult,
  BadRecord,
  ResultFile
} from '../types';

export class FileManager {
  private outputDir: string;
  private resultDir: string;
  private badRecordDir: string;
  private auditDir: string;

  constructor(baseDir: string = './output') {
    this.outputDir = path.resolve(baseDir);
    this.resultDir = path.join(this.outputDir, 'results');
    this.badRecordDir = path.join(this.outputDir, 'bad-records');
    this.auditDir = path.join(this.outputDir, 'audit');
    this.ensureDirectories();
  }

  private ensureDirectories(): void {
    [this.outputDir, this.resultDir, this.badRecordDir, this.auditDir].forEach(dir => {
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
        console.log(`[DIR_CREATED] ${dir}`);
      }
    });
  }

  private generateFileName(prefix: string, extension: string = 'json'): string {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    return `${prefix}_${timestamp}.${extension}`;
  }

  public saveProcessedResults(
    requests: SortingRequest[],
    responses: (SortingResponse | null)[],
    errors: string[]
  ): { resultFilePath: string; badRecordFilePath: string } {
    const processedAt = new Date().toISOString();
    const results: ProcessedResult[] = [];
    const badRecords: BadRecord[] = [];

    requests.forEach((request, index) => {
      const response = responses[index];
      const error = errors[index];

      if (error) {
        badRecords.push({
          rowIndex: index,
          request,
          errorType: this.classifyError(error),
          errorMessage: error,
          timestamp: processedAt
        });
        results.push({
          success: false,
          request,
          error,
          processedAt
        });
      } else if (response) {
        if (response.status === '失败') {
          badRecords.push({
            rowIndex: index,
            request,
            errorType: 'RULE_VALIDATION_FAILED',
            errorMessage: response.failedReason || '规则验证失败',
            timestamp: processedAt
          });
        }
        results.push({
          success: response.status !== '失败',
          request,
          response,
          processedAt
        });
      }
    });

    const resultFile: ResultFile = {
      totalCount: requests.length,
      successCount: results.filter(r => r.success).length,
      failedCount: results.filter(r => !r.success).length,
      badRecordCount: badRecords.length,
      processedAt,
      results,
      badRecords
    };

    const resultFileName = this.generateFileName('sorting_results');
    const resultFilePath = path.join(this.resultDir, resultFileName);
    fs.writeFileSync(resultFilePath, JSON.stringify(resultFile, null, 2), 'utf-8');
    console.log(`[FILE_SAVED] 处理结果已保存至: ${resultFilePath}`);

    const badRecordFileName = this.generateFileName('bad_records');
    const badRecordFilePath = path.join(this.badRecordDir, badRecordFileName);
    fs.writeFileSync(badRecordFilePath, JSON.stringify(badRecords, null, 2), 'utf-8');
    console.log(`[FILE_SAVED] 坏记录已保存至: ${badRecordFilePath}`);

    return { resultFilePath, badRecordFilePath };
  }

  private classifyError(error: string): string {
    if (error.includes('业务编号')) return 'INVALID_BUSINESS_NO';
    if (error.includes('时间')) return 'TIME_VALIDATION_ERROR';
    if (error.includes('规则版本')) return 'RULE_VERSION_ERROR';
    if (error.includes('操作人')) return 'OPERATOR_ERROR';
    return 'UNKNOWN_ERROR';
  }

  public saveSingleResult(response: SortingResponse): string {
    const fileName = `${response.businessNo}_${new Date().toISOString().replace(/[:.]/g, '-')}.json`;
    const filePath = path.join(this.resultDir, fileName);
    fs.writeFileSync(filePath, JSON.stringify(response, null, 2), 'utf-8');
    console.log(`[FILE_SAVED] 单笔处理结果已保存至: ${filePath}`);
    return filePath;
  }

  public saveBadRecord(badRecord: BadRecord): string {
    const fileName = this.generateFileName(`bad_${badRecord.request.businessNo}`);
    const filePath = path.join(this.badRecordDir, fileName);
    fs.writeFileSync(filePath, JSON.stringify(badRecord, null, 2), 'utf-8');
    console.log(`[FILE_SAVED] 坏记录已保存至: ${filePath}`);
    return filePath;
  }

  public appendAuditLog(auditLog: any): string {
    const fileName = `audit_log_${new Date().toISOString().split('T')[0]}.json`;
    const filePath = path.join(this.auditDir, fileName);

    let logs: any[] = [];
    if (fs.existsSync(filePath)) {
      const content = fs.readFileSync(filePath, 'utf-8');
      logs = JSON.parse(content);
    }
    logs.push(auditLog);
    fs.writeFileSync(filePath, JSON.stringify(logs, null, 2), 'utf-8');
    return filePath;
  }

  public getRecheckEntry(businessNo: string): string {
    const baseUrl = process.env.BASE_URL || 'http://localhost:3000';
    return `${baseUrl}/api/recheck/${businessNo}`;
  }

  public generateRecheckReport(businessNo: string, auditRecords: any[]): string {
    const report = {
      businessNo,
      recheckGeneratedAt: new Date().toISOString(),
      totalRecords: auditRecords.length,
      records: auditRecords,
      recheckEntry: this.getRecheckEntry(businessNo)
    };
    const fileName = `recheck_report_${businessNo}_${new Date().toISOString().replace(/[:.]/g, '-')}.json`;
    const filePath = path.join(this.auditDir, fileName);
    fs.writeFileSync(filePath, JSON.stringify(report, null, 2), 'utf-8');
    console.log(`[FILE_SAVED] 复核报告已生成: ${filePath}`);
    return filePath;
  }

  public readResultFile(filePath: string): ResultFile | null {
    try {
      const content = fs.readFileSync(filePath, 'utf-8');
      return JSON.parse(content);
    } catch (error) {
      console.error(`[FILE_READ_ERROR] 无法读取文件 ${filePath}:`, error);
      return null;
    }
  }

  public getLatestResultFile(): string | null {
    try {
      const files = fs.readdirSync(this.resultDir)
        .filter(f => f.startsWith('sorting_results_'))
        .sort()
        .reverse();
      return files.length > 0 ? path.join(this.resultDir, files[0]) : null;
    } catch {
      return null;
    }
  }

  public getLatestBadRecordFile(): string | null {
    try {
      const files = fs.readdirSync(this.badRecordDir)
        .filter(f => f.startsWith('bad_records_'))
        .sort()
        .reverse();
      return files.length > 0 ? path.join(this.badRecordDir, files[0]) : null;
    } catch {
      return null;
    }
  }
}

export const fileManager = new FileManager();
"}

