import { SortingRequest } from '../types';
import { ruleEngine } from '../engine/ruleEngine';
import { fileManager } from '../utils/fileManager';

const router = Router();

router.post('/sort', (req: Request, res: Response) => {
  try {
    const request: SortingRequest = req.body;
    console.log(`[API_REQUEST] 接收分拣请求 - 业务编号: ${request.businessNo}, 操作人: ${request.operator}`);
    const response = ruleEngine.process(request);
    fileManager.saveSingleResult(response);
    res.json({
      success: true,
      data: response
    });
  } catch (error) {
    console.error('[API_ERROR] 分拣请求处理失败:', error);
    res.status(500).json({
      success: false,
      error: '服务器内部错误',
      message: error instanceof Error ? error.message : '未知错误'
    });
  }
});

router.post('/sort/batch', (req: Request, res: Response) => {
  try {
    const { requests } = req.body;
    if (!Array.isArray(requests)) {
      return res.status(400).json({
        success: false,
        error: '请求格式错误，requests 应为数组'
      });
    }
    console.log(`[API_BATCH_REQUEST] 接收批量分拣请求 - 共 ${requests.length} 条记录`);
    const responses = requests.map(request => {
      try {
        return ruleEngine.process(request);
      } catch {
        return null;
      }
    });
    const errors = requests.map((request, index) => {
      const validation = ruleEngine.validateRequest(request);
      if (!validation.valid) return validation.error;
      const timeCheck = ruleEngine.checkTimeBoundary(request);
      if (!timeCheck.inRange) return timeCheck.error;
      if (responses[index]?.status === '失败') {
        return responses[index].failedReason;
      }
      return '';
    });
    const { resultFilePath, badRecordFilePath } = fileManager.saveProcessedResults(
      requests,
      responses,
      errors
    );
    res.json({
      success: true,
      data: {
        totalCount: requests.length,
        successCount: responses.filter(r => r && r.status !== '失败').length,
        failedCount: responses.filter(r => r?.status === '失败').length,
        responses,
        resultFilePath,
        badRecordFilePath
      }
    });
  } catch (error) {
    console.error('[API_ERROR] 批量分拣请求处理失败:', error);
    res.status(500).json({
      success: false,
      error: '服务器内部错误',
      message: error instanceof Error ? error.message : '未知错误'
    });
  }
});

router.get('/audit', (req: Request, res: Response) => {
  try {
    const auditLogs = ruleEngine.getAuditLogs();
    res.json({
      success: true,
      data: {
        total: auditLogs.length,
        logs: auditLogs
      }
    });
  } catch (error) {
    console.error('[API_ERROR] 获取审计记录失败:', error);
    res.status(500).json({
      success: false,
      error: '获取审计记录失败'
    });
  }
});

router.get('/audit/:id', (req: Request, res: Response) => {
  try {
    const { id } = req.params;
    const auditLog = ruleEngine.getAuditLogById(id);
    if (!auditLog) {
      return res.status(404).json({
        success: false,
        error: '审计记录不存在'
      });
    }
    res.json({
      success: true,
      data: auditLog
    });
  } catch (error) {
    console.error('[API_ERROR] 获取审计记录详情失败:', error);
    res.status(500).json({
      success: false,
      error: '获取审计记录详情失败'
    });
  }
});

router.post('/recheck/:auditId', (req: Request, res: Response) => {
  try {
    const { auditId } = req.params;
    const { operator } = req.body;
    if (!operator) {
      return res.status(400).json({
        success: false,
        error: '操作人不能为空'
      });
    }
    const recheckedRecord = ruleEngine.recheck(auditId, operator);
    if (!recheckedRecord) {
      return res.status(404).json({
        success: false,
        error: '审计记录不存在'
      });
    }
    res.json({
      success: true,
      data: recheckedRecord,
      message: '复核完成'
    });
  } catch (error) {
    console.error('[API_ERROR] 复核操作失败:', error);
    res.status(500).json({
      success: false,
      error: '复核操作失败'
    });
  }
});

router.get('/recheck/entry/:businessNo', (req: Request, res: Response) => {
  try {
    const { businessNo } = req.params;
    const auditLogs = ruleEngine.getAuditLogs().filter(log => log.businessNo === businessNo);
    const recheckEntry = fileManager.getRecheckEntry(businessNo);
    if (auditLogs.length === 0) {
      return res.status(404).json({
        success: false,
        error: '未找到该业务编号的审计记录'
      });
    }
    const reportPath = fileManager.generateRecheckReport(businessNo, auditLogs);
    res.json({
      success: true,
      data: {
        businessNo,
        auditCount: auditLogs.length,
        auditLogs,
        recheckEntry,
        reportPath
      }
    });
  } catch (error) {
    console.error('[API_ERROR] 获取复核入口失败:', error);
    res.status(500).json({
      success: false,
      error: '获取复核入口失败'
    });
  }
});

router.get('/results/latest', (req: Request, res: Response) => {
  try {
    const resultFilePath = fileManager.getLatestResultFile();
    const badRecordFilePath = fileManager.getLatestBadRecordFile();
    if (!resultFilePath) {
      return res.status(404).json({
        success: false,
        error: '暂无处理结果文件'
      });
    }
    const resultFile = fileManager.readResultFile(resultFilePath);
    res.json({
      success: true,
      data: {
        resultFilePath,
        badRecordFilePath,
        resultFile
      }
    });
  } catch (error) {
    console.error('[API_ERROR] 获取最新结果失败:', error);
    res.status(500).json({
      success: false,
      error: '获取最新结果失败'
    });
  }
});

router.get('/health', (req: Request, res: Response) => {
  res.json({
    success: true,
    data: {
      status: 'running',
      timestamp: new Date().toISOString(),
      service: '保险理赔材料分拣API'
    }
  });
});

export default router;
"}

