interface TestResult {
  name: string;
  category: string;
  passed: boolean;
  expectedStatus: string;
  actualStatus: string;
  message: string;
  response?: SortingResponse;
}

function runAcceptanceTests(): void {
  console.log('');
  console.log('========================================');
  console.log('  保险理赔材料分拣API - 验收测试');
  console.log('========================================');
  console.log('');

  const results: TestResult[] = [];
  const allRequests: SortingRequest[] = [];
  const allResponses: (SortingResponse | null)[] = [];
  const allErrors: string[] = [];

  testCases.forEach((testCase, index) => {
    console.log(`[测试用例 ${index + 1}/${testCases.length}] ${testCase.name}`);
    console.log(`  分类: ${testCase.category}`);

    const response = ruleEngine.process(testCase.request);
    allRequests.push(testCase.request);
    allResponses.push(response);
    allErrors.push(response.status === '失败' ? (response.failedReason || '') : '');

    let passed = response.status === testCase.expectedStatus;

    if (passed && testCase.expectedContains) {
      const actualReason = response.failedReason || response.lockReason || response.supplementItems?.join('、') || '';
      passed = actualReason.includes(testCase.expectedContains);
    }

    const result: TestResult = {
      name: testCase.name,
      category: testCase.category,
      passed,
      expectedStatus: testCase.expectedStatus,
      actualStatus: response.status,
      message: passed ? '通过' : `期望: ${testCase.expectedStatus}, 实际: ${response.status}`,
      response
    };

    results.push(result);

    console.log(`  期望状态: ${testCase.expectedStatus}`);
    console.log(`  实际状态: ${response.status}`);
    if (response.failedReason) console.log(`  失败原因: ${response.failedReason}`);
    if (response.lockReason) console.log(`  锁定原因: ${response.lockReason}`);
    if (response.supplementItems?.length) console.log(`  需补充: ${response.supplementItems.join('、')}`);
    console.log(`  规则版本: ${response.ruleVersion}`);
    console.log(`  操作人: ${response.operator}`);
    console.log(`  审计ID: ${response.auditRecord.id}`);
    console.log(`  结果: ${passed ? '✓ 通过' : '✗ 失败'}`);
    console.log('');
  });

  console.log('----------------------------------------');
  console.log('  测试重复请求稳定性');
  console.log('----------------------------------------');

  const duplicateRequest: SortingRequest = {
    businessNo: 'CL2025999999',
    objectStatus: 'NORMAL',
    timeWindow: {
      start: '2025-06-01T00:00:00',
      end: '2025-06-30T23:59:59'
    },
    ruleVersion: 'v2.0',
    operator: '重复测试员'
  };

  const response1 = ruleEngine.process(duplicateRequest);
  const response2 = ruleEngine.process(duplicateRequest);
  const isStable = response1.status === response2.status && response1.auditRecord.id === response2.auditRecord.id;

  console.log(`  第一次请求状态: ${response1.status}`);
  console.log(`  第二次请求状态: ${response2.status}`);
  console.log(`  审计ID一致: ${response1.auditRecord.id === response2.auditRecord.id}`);
  console.log(`  稳定性测试: ${isStable ? '✓ 通过 - 重复请求返回稳定结论' : '✗ 失败'}`);
  console.log('');

  console.log('----------------------------------------');
  console.log('  保存结果文件和坏记录隔离');
  console.log('----------------------------------------');

  const { resultFilePath, badRecordFilePath } = fileManager.saveProcessedResults(
    allRequests,
    allResponses,
    allErrors
  );

  console.log(`  结果文件: ${resultFilePath}`);
  console.log(`  坏记录文件: ${badRecordFilePath}`);
  console.log('');

  console.log('----------------------------------------');
  console.log('  测试复核入口');
  console.log('----------------------------------------');

  const firstAuditId = results[0]?.response?.auditRecord.id;
  if (firstAuditId) {
    const recheckedRecord = ruleEngine.recheck(firstAuditId, '复核主管');
    if (recheckedRecord) {
      console.log(`  复核记录ID: ${recheckedRecord.id}`);
      console.log(`  复核人: ${recheckedRecord.recheckedBy}`);
      console.log(`  复核时间: ${recheckedRecord.recheckedTime}`);
      console.log(`  已复核: ${recheckedRecord.isRechecked ? '✓ 是' : '否'}`);
    }
  }

  const recheckEntry = fileManager.getRecheckEntry('CL2025000001');
  console.log(`  复核入口URL: ${recheckEntry}`);
  console.log('');

  console.log('========================================');
  console.log('  测试结果汇总');
  console.log('========================================');
  console.log('');

  const categories = [...new Set(results.map(r => r.category))];
  categories.forEach(category => {
    const categoryResults = results.filter(r => r.category === category);
    const passed = categoryResults.filter(r => r.passed).length;
    const total = categoryResults.length;
    console.log(`  [${category}] ${passed}/${total} 通过`);
  });

  const totalPassed = results.filter(r => r.passed).length;
  const totalTests = results.length;
  const allPassed = totalPassed === totalTests && isStable;

  console.log('');
  console.log(`  总计: ${totalPassed}/${totalTests} 测试用例通过`);
  console.log(`  稳定性测试: ${isStable ? '通过' : '失败'}`);
  console.log('');
  console.log(`  整体验收结果: ${allPassed ? '✓ 全部通过 ✓' : '✗ 存在失败用例'}`);
  console.log('');
  console.log('========================================');

  if (!allPassed) {
    process.exit(1);
  }
}

ruleEngine.clearCache();
runAcceptanceTests();
"}

